insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 0, '地理空间数据模型可以归纳为哪三个层次？', '概念模型、逻辑模型、数学模型', '概念数据模型、逻辑数据模型、物理数据模型', '对象模型、场模型、网络模型', '矢量数据模型、栅格数据模型、拓扑模型', 'B', 'A项错误，空间数据模型不包括数学模型，抽象的第三个层次应为物理数据模型。B项正确，对现实世界抽象建模得到空间数据模型，其可归纳为概念数据模型、逻辑数据模型和物理数据模型三个层次。C项错误，对象模型、场模型和网络模型是具体的概念数据模型，不能代表抽象的三个层次。D项错误，矢量和栅格属于底层数据结构的表达，不是系统抽象的层次。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 1, '以下哪项不是地理空间实体的四个基本特征之一？', '空间位置特征', '属性特征', '空间关系特征', '数据结构特征', 'D', 'A项错误，空间位置特征（几何特征）是四大基本特征之一。B项错误，属性特征（非空间特征）也是实体的基本特征。C项错误，空间关系特征属于实体的四大基本特征之一。D项正确，空间实体具有4个基本特征，即空间位置特征、属性特征、时间特征和空间关系特征，并不包括数据结构特征。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 2, '地理信息系统描述空间抽象过程的最高层次是？', '概念模型', '逻辑模型', '物理模型', '网络模型', 'A', 'A项正确，概念模型是地理数据的语义解释，从计算机系统角度看是系统抽象的最高层。B项错误，逻辑模型是系统抽象的中间层。C项错误，物理模型是系统抽象的最底层。D项错误，网络模型属于具体的概念模型类型之一。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 3, '适合用于对具有明确边界的离散地理现象（如建筑物、道路）进行建模的是？', '场模型', '时空立方体模型', '对象模型', '像素数据模型', 'C', 'A项错误，场模型用于连续变量的表达。B项错误，时空立方体处理带有时间维度的动态变化。C项正确，对象模型把现象作为独立的对象，一般适合于具有明确边界和离散地理现象的建模，如建筑物和道路。D项错误，像素数据（影像）主要反映地表的栅格覆盖情况，非针对离散对象的专门逻辑。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 4, '把地理空间现象作为连续的变量或体来看待的数据模型是？', '对象模型', '场模型', '网络模型', '时空模型', 'B', 'A项错误，对象模型处理独立分布的空域对象。B项正确，场模型把地理空间中的现象作为连续的变量或体来看待，如大气污染和地表温度等。C项错误，网络模型强调多地理现象之间的连通情况。D项错误，时空模型重点处理随时间变化的过程。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 5, '不属于二维场数据模型常用具体表示方法的是？', '等值线', '不规则分布的点', '拓扑相交连通链', '规则矩形区（格网单元）', 'C', 'A项错误，等值线是场模型表征连续插值的常用表示方法。B项错误，不规则分布的点通过空间内插求得属性，属于常用场模型。C项正确，二维场模型通常有6种描述形式，拓扑连通链多属于网络或对象模型，不在此列。D项错误，规则矩形区即格网单元，是场模型的典型描述方式。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 6, '与对象模型在描述不连续现象上相似，但更需要考虑地理现象之间连通情况与交互作用的模型是？', '场模型', '多维数据模型', '网络模型', '影像数据模型', 'C', 'A项错误，场模型主要描述连续现象。B项错误，多维模型侧重于多于两个属性维度的变化。C项正确，网络模型描述不连续地理现象，但不同之处在于它需考虑通道相互连接的多个地理现象的连通情况与交互作用。D项错误，影像数据属于栅格像素数据表示。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 7, '某地出租车乘客的上下车位置存在多种可能，且该位置的乘客数量也不确定，这属于时空模型的哪种变化形式？', '属性不变而空间位置发生变化', '空间位置和属性同时变化', '属性随时间变化而位置不变', '时间属性固化而空间维度增加', 'B', 'A项错误，这属于个人普通出行轨迹的特征。B项正确，出租车乘客上下车位置可能变化，且乘客数量（属性）不定，属于空间位置和属性均变化的形式。C项错误，这是固定地铁站点刷卡人数变动的特征。D项错误，资料未提到该种时空变化形式。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 8, '属于连续型时空数据模型的是？', '时空立方体模型', '序列快照模型', '时空棱柱模型', '拓扑空间模型', 'A', 'A项正确，时空立方体模型以三维空间为基础并以Z轴表示时间，在任何位置时间都能找到对应单元，属于连续型时空数据模型。B项错误，序列快照是常用表达形式，未指出其具备连续多面体特性。C项错误，基于时空棱柱的数据模型仅对移动对象轨迹表达，属于离散型时空数据模型。D项错误，拓扑模型反映相邻关系，不是时空模型。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 9, '若研究区域内的温度随时间变化，且同时随海拔高度两个变量发生变化，通常需要使用几维模型表达？', '二维模型', '三维模型', '四维模型', '五维模型', 'C', 'A项错误，二维无法体现时间和高程。B项错误，仅随时间或仅随高程变化之一时构建三维即可。C项正确，若温度表达式为Tem=F(x, y, h, t)，包含了XY二维空间、高程h和时间t四个变量，这就需要构建四维模型。D项错误，四变量对应四维，不需要五维。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 10, '实现空间数据概念模型到物理模型转换的桥梁是？', '数学模型', '逻辑数据模型', '面向对象程序', 'UML语言', 'B', 'A项错误，空间数据模型中不包括数学模型抽象层。B项正确，空间逻辑数据模型是实现空间数据概念模型到空间数据物理模型的桥梁。C项错误，面向对象仅是实现逻辑模型的方法之一。D项错误，UML是表示模型设计的方法工具，非概念桥梁本身。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 11, '提取建筑物的高度和面积等属性信息，以用于城市规划，这在空间数据逻辑建模中属于？', '实体属性的逻辑建模', '实体关系的逻辑建模', '实体行为的逻辑建模', '网络拓扑建模', 'A', 'A项正确，对地理实体的非空间属性（高度、面积）进行提取和抽象，属于实体属性的逻辑建模。B项错误，关系建模涉及多个对象之间的关联，如一对多。C项错误，行为建模定义实体的运行规则。D项错误，网络拓扑用于分析路径连通。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 12, '在一般关系的逻辑建模中，农户与多个宗地之间的关系属于？', '一对一关系', '多对多关系', '一对多关系', '拓扑关系', 'C', 'A项错误，一个农户可拥有多个地块。B项错误，农户和居住区才是多对多关系。C项正确，一个农户可以有多个地块，但一个地块只能属于一个农户，这是典型的一对多关系。D项错误，这属于一般关系，不涉及几何拓扑关联。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 13, '约束“某条道路只能向北单行”，这属于空间逻辑数据建模的哪一类？', '实体属性的逻辑建模', '实体关系的逻辑建模', '实体行为的逻辑建模', '几何特征的逻辑建模', 'C', 'A项错误，属性建模侧重于非空间静态数值如高度。B项错误，关系建模侧重于对象所有权和从属。C项正确，定义实体交互规则与复杂限制条件（如道路单行、污染物随风向扩散）属于实体行为的逻辑建模。D项错误，几何类型决定建筑物是用点还是面表示，与单行限制无关。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 14, '面向对象方法中，把一组属于不同类中的若干对象组合起来，形成一个更高级别的复合对象（如宗地）的过程称为？', '概括', '聚集', '联合', '分类', 'B', 'A项错误，概括是将具有相同属性的类抽象为超类。B项正确，聚集是把不同类对象组合成复合对象，如将地籍权属界线与内部建筑物聚集为“宗地”类。C项错误，联合是对同一类中的具体对象进行合并。D项错误，分类是相同对象的归类。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 15, '饭店类因为是建筑物类的子类，因而直接获得了房屋主、地址等属性，这利用了面向对象技术的什么语义工具？', '多方继承', '传播', '单一继承', '联合', 'C', 'A项错误，饭店直接继承自唯一的建筑物超类，并非多方继承。B项错误，传播是从子对象提取位置信息强制给父对象的工具。C项正确，饭店类作为建筑物的子类，继承这些共有的属性和操作，这属于服务于概括的继承工具。D项错误，联合是相同类的对象合并。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 16, '“运河”作为“人工交通线”和“河流”的共同子类，同时继承两者的方法，这在面向对象逻辑模型中称为？', '聚集', '传播', '单一继承', '多方继承', 'D', 'A项错误，聚集是构成复杂实体的过程。B项错误，传播是提取坐标属性。C项错误，单一继承只有一个直接父类。D项正确，运河允许多于一个直接父类，同时继承“交通线”和“水系”的属性方法，被称为多方继承。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 17, '为了保证数据库一致性，多边形的位置坐标不直接表达，而是从其构成的弧段和结点中提取，这种面向对象的语义手段叫？', '传播', '联合', '封装', '概括', 'A', 'A项正确，传播是一种强制性的手段，使复杂对象的属性不单独描述，而是从子对象中提取，以此保证数据库一致性。B项错误，联合是将对象合并。C项错误，封装是隐藏方法内部实现。D项错误，概括是产生超类。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 18, '矢量空间几何图形数据中，最为基本、并可用来构建其它所有类型几何图形要素的数据类型是？', '面', '线', '点', '体', 'C', 'A、B、D项错误，线由点连成，面由闭合线构成，体由面构建。C项正确，在空间几何图形数据中，点是最为基本的几何图形要素，其它类型的几何图形要素都是基于点数据构建。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 19, '三维矢量线要素的构建，在本质上是由什么决定的？', '线条的长度和连接顺序', '点的高程属性及点的序列关系', '三维多边形的相交特性', '像素单元的体积大小', 'B', 'A项错误，缺乏对高程维度构成的解释。B项正确，观察二三维特征可发现，三维线的构建本质上是由点的高程属性及点的序列关系所决定的。C项错误，线不依赖于多边形而存在。D项错误，像素是栅格数据特征。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 20, '关于影像数据（像素数据）空间分辨率的说法，哪项是正确的？', '像元越小，空间分辨率一定越高', '空间分辨率仅由影像的显示比例尺决定', '栅格数据的空间分辨率是由其比例尺和像元的分辨率共同决定的', '像元大小会随着显示器上的放大操作而实际改变', 'C', 'A项错误，分辨率不单取决于像元极小，还受比例尺影响。B项错误，仅仅比例尺不足以决定。C项正确，影像像元越小不等于分辨率越高，栅格数据的空间分辨率是由其比例尺和像元的分辨率共同决定的。D项错误，像元在地面上实际覆盖的尺寸并不会因显示放大或缩小而改变。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 21, '当栅格单元中出现多个地物时，决定该栅格单元属性值的原则是什么？', '永远取左上角像素点的值', '永远取最小地物的值', '尽量保持其真实性，如取中心点或整体区域取值', '随机取平均值', 'C', 'A项错误，无此选取方法。B项错误，无强制取最小地物值的规定。C项正确，决定栅格单元值时应尽量保持其真实性，常用的方法包括取像元中心点或从整体区域取值。D项错误，不随机取平均值。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 22, '在空间图形保持连续状态的变形（如橡皮拉伸）中，哪种空间关系能保持不变？', '形状大小关系', '顺序空间关系', '度量空间关系', '拓扑空间关系', 'D', 'A项错误，形状和大小会随图形的变形而改变。B项错误，顺序关系方位可能会改变。C项错误，度量距离会随着拉伸改变。D项正确，地图上的拓扑关系是指图形在变形时，其邻接、包含等图形关系保持不变的性质。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 23, '在拓扑空间关系中，结点与弧段之间的关联关系属于？', '邻接关系', '连通关系', '包含关系', '关联关系', 'D', 'A项错误，邻接属于同类元素间的关系。B项错误，连通属于弧段与弧段之间的关系。C项错误，包含强调不同级别如多边形内有岛。D项正确，不同类元素（如结点和弧段，或者弧段和多边形）之间的拓扑关系称为关联关系。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 24, '两个分离的实体变压器和电线杆，在投影至平面上时正好位置一致，这属于点－点实体的哪种空间关系？', '相邻', '重合', '相交', '包含', 'B', 'A项错误，点点之间没有相邻关系。B项正确，点实体和点实体之间只存在相离和重合两种关系，投影到一点即重合关系。C项错误，点与点没有相交关系。D项错误，点与点没有包含关系。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 25, '供水主干管道与次干管道相连，这属于线实体与线实体的什么空间关系？', '相邻（连通）', '相离', '包含', '重合', 'A', 'A项正确，线实体与线实体间供水主干与次干管道这种连接属于相邻（连通）关系。B项错误，管道连通并不是分离的。C项错误，次干并非包含于主干内。D项错误，并未占据完全一样的坐标路径。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 26, '下列关于“度量空间关系”的描述，错误的是？', '主要指空间实体间的距离关系', '可以按欧几里德距离进行定量计算', '它是一种极其稳定的关系，不随投影和几何变换而改变', '可以应用“远近”等概念进行定性描述', 'C', 'A项错误，此描述正确，度量指距离关系。B项错误，此描述正确，可用欧式距离定量。C项正确，距离值和顺序关系类似，会随投影和几何变换而变化，因而不是稳定的。D项错误，此描述正确，可用“远近”定性描述。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 27, '从概念建模的角度，采用分段函数给各坐标点映射一个恒定取值，从而对带有不同林分覆盖的森林建模，属于什么观点？', '对象模型', '时空模型', '场模型', '网络模型', 'C', 'A项错误，对象模型是直接定义界限得到多边形边界的方法。B项错误，未涉及随时间推演的过程。C项正确，将森林建模为分段函数并映射至各点属性的方法，体现了场模型把现象当连续变量的观点。D项错误，与路径分析无关。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 28, '在遥感领域，利用卫星和飞机上的传感器收集地表数据时，占据主导地位的概念模型是？', '网络模型', '场模型', '对象模型', 'UML模型', 'B', 'A项错误，网络模型不适合广泛连续覆盖。B项正确，遥感领域主要利用传感器收集地表连续变化数据，此时场模型是占主导地位的。C项错误，对象模型主要应用于明确边界如道路和地块等。D项错误，UML属于逻辑设计方法。', datetime('now'));
insert into exercises (chapter_id, exercise_index, question, option_a, option_b, option_c, option_d, correct_answer, explanation, updated_at) values ('chapter-3', 29, '在处理空间数据逻辑模型的顺序关系（如上下左右方位）时，当前GIS系统的通常做法是？', '通过建立强大的几何计算引擎完美重构', '将其转化为唯一的拓扑网络进行记录', '由于计算复杂且随投影变换发生改变，一般不明确描述和表达', '将距离远近函数作为其计算基础', 'C', 'A项错误，这种计算极其复杂，尚没有很好的解决方法。B项错误，顺序和拓扑并非一回事。C项正确，由于计算复杂，且顺序空间关系会随空间数据的投影及几何变换而发生变化，所以现在的GIS中一般不对其进行描述和表达。D项错误，距离远近属于度量空间关系的范畴。', datetime('now'));
